    private fun Map<String, Any?>.toLogString(): String {
        return entries.joinToString(
            separator = ", ",
            prefix = "{",
            postfix = "}"
        ) { (key, value) ->
            "$key=${value.toPrettyString()}"
        }
    }

    private fun Any?.toPrettyString(): String = when (this) {
        null -> "null"
        is String -> "\"${escape() }\""
        is CharSequence -> "\"${toString().escape()}\""
        is Map<*, *> -> entries.joinToString(prefix = "{", postfix = "}") { (k, v) ->
            "${k.toString().escape()}=${v.toPrettyString()}"
        }
        is Iterable<*> -> joinToString(prefix = "[", postfix = "]") { it.toPrettyString() }
        is Array<*> -> joinToString(prefix = "[", postfix = "]") { it.toPrettyString() }
        else -> toString()
    }

    private fun String.escape(): String {
