package com.example.app.logging

import okhttp3.Interceptor
import okhttp3.Response
import okio.Buffer
import java.nio.charset.Charset
import java.util.UUID
import java.util.concurrent.TimeUnit

class LoggingInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val requestId = UUID.randomUUID().toString()
        val startNs = System.nanoTime()

        val requestHeaders = request.headers.toMultimap().mapValues { (_, values) -> values.joinToString(", ") }
        val requestBodyString = request.body?.let { bodyToString(it) }

        AppLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = requestHeaders,
            body = requestBodyString,
            requestId = requestId
        )

        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            val responseHeaders = response.headers.toMultimap().mapValues { (_, values) -> values.joinToString(", ") }
            val responseBodyString = response.peekBody(Long.MAX_VALUE).string()

            AppLogger.logApiResponse(
                method = request.method,
                url = request.url.toString(),
                statusCode = response.code,
                headers = responseHeaders,
                body = responseBodyString,
                durationMs = tookMs,
                requestId = requestId
            )
            response
        } catch (t: Throwable) {
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            AppLogger.logException(
                tag = "API",
                throwable = t,
                message = "API request failed",
                extra = mapOf(
                    "method" to request.method,
                    "url" to request.url.toString(),
                    "durationMs" to tookMs,
                    "requestId" to requestId
                )
            )
            throw t
        }
    }

    private fun bodyToString(body: okhttp3.RequestBody): String {
        return try {
            val buffer = Buffer()
            body.writeTo(buffer)
            val charset: Charset = body.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            buffer.readString(charset)
        } catch (e: Exception) {
            "Unable to read request body: ${e.message}"
        }
    }
}

