package com.example.app.auth

import com.example.app.logging.AppLogger

class AuthRepository {
    fun login(username: String, password: String): Boolean {
        AppLogger.logAuthAttempt(username = username, success = false, reason = "Attempt started")
        return try {
            val success = authenticate(username, password)
            if (success) {
                AppLogger.logAuthAttempt(username = username, success = true, reason = "Credentials accepted")
            } else {
                AppLogger.logAuthAttempt(username = username, success = false, reason = "Invalid credentials")
            }
            success
        } catch (t: Throwable) {
            AppLogger.logException(
                tag = "Auth",
                throwable = t,
                message = "Authentication exception",
                extra = mapOf("username" to username)
            )
            false
        }
    }

    private fun authenticate(username: String, password: String): Boolean {
        return username.isNotBlank() && password.isNotBlank() && password.length >= 8
    }
}

package com.example.app

import android.app.Application
import com.example.app.logging.AppLogger
import com.example.app.logging.LoggingInterceptor
import okhttp3.OkHttpClient
import timber.log.Timber

class MyApp : Application() {
    override fun onCreate() {
        super.onCreate()
        AppLogger.initialize(this, enableLogging = true, enableVerboseLogging = true)
        Timber.i("Application started")

        val client = OkHttpClient.Builder()
            .addInterceptor(LoggingInterceptor())
            .build()

        AppLogger.i("App", "OkHttp client initialized", mapOf("client" to client.javaClass.simpleName))
    }
}